import { ApiProperty, ApiPropertyOptional } from "@nestjs/swagger";

import {
  NumberField,
  StringFieldOptional,
  UUIDField,
} from "../../../decorators/field.decorators.ts";

export class CreatePaymentDto {
  @ApiProperty({ description: "Payment amount", minimum: 0 })
  @NumberField({ min: 0 })
  amount!: number;

  @ApiPropertyOptional({
    description: "Currency code",
    example: "BTN",
    default: "BTN",
  })
  @StringFieldOptional({ maxLength: 3 })
  currency?: string;

  @StringFieldOptional({ maxLength: 500 })
  description?: string;

  @ApiPropertyOptional({ description: "Associated pool ID" })
  @UUIDField({ required: false })
  poolId?: string;
}
